// รับ input จาก node ก่อนหน้า
const inputData = items[0].json;

// ดึงค่าจากฟิลด์
const userInputArray = inputData["userInput"];
const messageIdArray = inputData["messageId"];

// ตรวจสอบว่าเป็น array แล้วรวมข้อความ
const allUserInput = Array.isArray(userInputArray) 
  ? userInputArray.join(" ") 
  : "";

const allMessageId = Array.isArray(messageIdArray) 
  ? messageIdArray.join(" ") 
  : "";

// สร้างผลลัพธ์ใหม่
return [
  {
    json: {
      allUserInput,
      allMessageId
    }
  }
];

function checkMessageId() {
  try {
    // ดึงข้อมูล allUserInput และ allMessageId
    const allUserInput = $input.first().json.allUserInput || [];
    const allMessageId = $input.first().json.allMessageId || [];

    // ดึงข้อความและ messageId ล่าสุด
    const lastUserInput = allUserInput[allUserInput.length - 1];
    const lastMessageId = allMessageId[allMessageId.length - 1];

    // ตรวจสอบว่ามีข้อมูล 233.array และเข้าถึงได้
    let bundleData;
    if ($input.first().json['233'] && Array.isArray($input.first().json['233'].array)) {
      bundleData = $input.first().json['233'].array[9];
    } else {
      throw new Error('ไม่พบข้อมูล 233.array หรือไม่มีข้อมูลลำดับที่ 9');
    }

    // ดึง messageId จาก Google Sheet bundle
    const sheetMessageId = bundleData?.messageId || null;

    // เปรียบเทียบโดยแปลงผลเป็น Boolean อย่างชัดเจน
    const isMessageIdMatched = lastMessageId === sheetMessageId ? true : false;

    return {
      json: {
        ...$input.first().json,
        isMessageIdMatched,
        lastUserInput,
        lastMessageId,
        sheetMessageId,
        proceedToOpenAI: isMessageIdMatched
      }
    };

  } catch (error) {
    return {
      json: {
        ...$input.first().json,
        error: true,
        errorMessage: error.message,
        isMessageIdMatched: false, // กันไว้ไม่ให้ทะลุ
        proceedToOpenAI: false
      }
    };
  }
}

return checkMessageId();

function createTelegramMessage() {
  const output = $input.first().json.clean_text || "ไม่มีข้อความตอบกลับ";

  return {
    json: {
      text: output
    }
  };
}

